from string_utils.generation import roman_range

def test_roman_range_invalid_upper_limit():
    try:
        output = list(roman_range(4000))  # This should raise an error in the baseline
        print(f"Output: {output}")  # Should not reach this line as ValueError is expected
    except ValueError as ve:
        print(f"Raised ValueError as expected: {ve}")
    except OverflowError as oe:
        print(f"Raised OverflowError (not expected): {oe}")
